INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L094$$, 2026, $$This funding line is for procurement of Army Long-range Persistent Surveillance Mobile (ALPS-M).

 The ALPS-M system is a persistent, passive air surveillance sensor system that provides long-range, 360-degree surveillance against conventional fixed and rotary wing aircraft, UAS, and cruise missiles. The
 system consists of a 20m tower, MIL-STD generator, and all system electronics integrated onto the footprint of a family of medium tactical vehicles (FMTV) platform. The system operates as additional sensors
 on existing air defense networks and can connect to multiple command and control (C2) systems. The system is a key component of the Army Integrated Air and Missile Defense (AIAMD) architecture, providing
 critical air surveillance of the forward areas, enabling greater survivability for maneuver forces.

 The requirement for the ALPS-M is documented in the ALPS Capability Development Document (CDD) Annex.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                                  Date: April 2026
