INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L104$$, 2027, $$The 3rd Generation Forward Looking Infrared (3GEN FLIR) B-Kit incorporates Mid Wave Infrared and Long Wave Infrared digital video and the electronic interfaces required to integrate the 3GEN FLIR
 technology with the host platform sensor. Incorporation of the 3GEN FLIR technology improves sensor performance restoring sensor overmatch which enhances the warfighters' survivability and lethality through
 increased identification range performance, while enabling the detection of difficult or obscured targets and faster threat detection through automated processes; positioning 3GEN FLIR as the lead sensor to
 provide the Army's path forward for AI/ML sensor capabilities for ground platforms. The 3GEN FLIR B-Kit design represents a common sensor solution for integration across US Army FLIR sensor systems
 providing the Army the opportunity to achieve economies of scale and reduce procurement and sustainment costs. Currently, the 3GEN FLIR B-Kit program's procurement efforts are focused on maturing the
 3GEN FLIR production line and the XM30 and FALCONS requirements.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                            Date: April 2026
