INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L125$$, 2027, $$BE4171: The ARNG DLP (Distributed Learning Program). The ARNG DLP provides online capabilities in communities nationwide to support training and readiness of Soldiers and units, assisting in generation
