INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L175$$, 2027, $$This program procures Base-level commercially available equipment from a list authorized by the Table of Distribution and Allowances (TDA) for Army activities but is not Army centrally managed or purchased.
 The equipment supports activities typically performed by garrisons, such as material and cargo handling, engineering and public works, port and terminal operations support, video teleconference and related
 information technology/audio visual equipment. Funds procure new investment items or replacements for existing equipment that is over-aged, obsolete, or beyond economical repair.

 The Base Level Commercial Equipment (BCE) programs enables the Department of the Army Criminal Investigation Division (DACID) which is primarily OMA funded to obtain certain investment end items such
 as non-standard, off the shelf equipment. The program procures new or lifecycle replacement of existing equipment which are outdated.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                                  Date: April 2026
