INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L117$$, 2026, $$The CECOM Software Engineering Center (SEC) delivers secure, and modern software services for the Army. As part of that, SEC provides depot maintenance for legacy weapon systems supporting
 Intelligence, Electronic Warfare, Sensors and Aviation, Mission Command, Communications and Networks, and Fires and Radars programs. CECOM SEC is also continuing development on its Software
 Engineering Environment (SE2), which will support Continuous Integration/Continuous Delivery (CI/CD) and Army software modernization for weapon systems. Under CI/CD, software no longer transitions to
 sustainment. Instead, software follows a Continuous Integration/Continuous Delivery (CI/CD) model which allows for software solutions that automate building, testing, and deploying code changes. Investments
 in equipment and technology position CECOM SEC to support the Army's Directive to improve agility and lean processes under a CI/CD environment while providing best practices to manage these efforts
 efficiently across the Army. In support of legacy weapon systems, policy requires that Life Cycle Management Centers (LCMCs) provide upgrades and replacement of obsolete equipment. Significant portions of
 host and network equipment are no longer economically repairable and/or are reaching obsolescence. There is a requirement to respond to emergency requests from the field for Software Engineering support,
 to maintain operational readiness of deployed weapon systems. With host computers and peripherals having a life span of approximately five years and SEC performing its mission over a continuous period of
 time beyond five years, equipment and labs must be replaced and/or upgraded regularly to handle obsolescence and take advantage of the continual improvements in technology that are indigenous to high-
 technology based weapon systems and their software support environments. SEC must purchase these items to meet systems' mission requirements.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                            Date: April 2026
