INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L142$$, 2027, $$AN/PSS-14C Mine Detecting Set is a lightweight self-contained handheld mine detector system that is operated by a single Soldier. AN/PSS-14C is an enabler for Soldier Lethality as it guarantees Soldier
 maneuverability by enhancing the probability and speed of detection of buried landmines and IEDs allowing for increased speed of dismounted operations making the unit more efficient and lethal. AN/PSS-14C
 consists of a Decoupled Ground Penetrating Radar (GPR) and Metal Detector (MD), which provides enhanced detection of hard to find, low/no metal IED components, along with traditional conventional mines.
 This item is Code A, approved for service use.

 Army Acquisition Objective (AAO) is 19,851 sets.

 Justification:
 R68200 has no funding request in FY 2027.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                           Date: April 2026
