INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L097$$, 2026, $$FY 2027 has no funding request under KA3500.

 FY 2027 and out-year funding for K36400, K36402, K36414 were realigned to parent K81500 Advanced Situational Awareness Systems, under new Standard Study Numbers: K81514 (ENVG-B), K91511(SBMC)
 and K81513 (BiNOD).

 This funding is directly aligned to the Army Soldier Lethality, Modernization LOE 3 Integrated Visual Augmentation System.

 Night Vision Devices (KA3500) is a summary budget line including the following programs:

 (1) K36400 - This funding line is directly aligned to the Army Soldier Lethality Modernization Priority in support of situational awareness for the Close Area Combat Force. The Enhanced Night Vision Goggle-
 Binocular (ENVG-B) system is a modular helmet-mounted, passive electro-optical fused sensor imaging device in a binocular configuration. The system integrates dual Image Intensification (I2) sensors with
