INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1611_L040$$, 2027, $$The Bulk Fuel Vessel (T-AOT) program will procure tankers to support the transportation and distribution of bulk petroleum products in support of U.S. Navy and joint force operations. These tankers will operate
 under the Military Sealift Command (MSC) to transport fuel from shore-based facilities to forward operating areas and provide at-sea fuel transfer capability in support of fleet logistics operations. The tankers will
 augment the Navy's existing fleet oiler force by providing additional capacity to move fuel forward and sustain naval forces operating at extended distances from established logistics hubs.

 The tankers will be capable of supporting consolidated replenishment (CONSOL) operations, enabling commercial or logistics tankers to transfer fuel to fleet oilers at sea. This capability allows fleet oilers to
 remain on station for longer periods and continue conducting underway replenishment operations to support combatant ships, rather than returning to port to reload fuel. By enabling oilers to remain forward
 deployed, the program increases the endurance and operational reach of naval forces.

 The Bulk Fuel Vessel program supports the Navy's distributed maritime operations concept by strengthening the logistics network required to sustain forces across large operating areas, particularly in the Indo-
 Pacific region. The tankers will provide additional fuel transport capacity, improve operational flexibility, and enhance the resilience of the Navy's logistics force by reducing reliance on fixed infrastructure and
 enabling greater integration with partner nation logistics capabilities.

 The Department of the Navy intends to explore foreign shipbuilding opportunities for the FY27 and FY28 ships.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                       Date: April 2026
