INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1611_L040_v18$$, 2027, $$The Submarine Tender will be designed to conduct steady state and wartime sustained, forward-based / expeditionary tending, resupply, depot and intermediate level repair operations on submarines while
 anchored or pier side. In steady state, the Submarine Tender will provide pier side support in a forward deployed submarine homeport, providing sustained repair, supply, weapons handling, and tending
 operations for submarines. The Submarine Tender will support deployed VIRGINIA class (VCS), COLUMBIA class (CLB) and future generation submarines. In addition, the submarine tender will provide
 radiological emergency response. Submarine Tenders will be built to commercial standards, including American Bureau of Shipping (ABS) rules and U.S. Coast Guard (USCG) regulations, and will utilize
 Commercial off-the-shelf (COTS) and Government Furnished Program of Record (POR) systems and equipment as well as Military Specification standards for designated areas including Nuclear Support Facility
 (NSF).

