INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L129$$, 2026, $$The Department of War (DoW) High Performance Computing (HPC) Modernization Program, managed by the Army, supports the needs of all services for technological superiority and military dominance on
 the battlefield by providing advanced computational services to U.S. weapons system scientists and engineers. By exploiting continuous advances in high performance computing technology, the Defense
 Research, Development, Test and Evaluation (RDT&E), and acquisition engineering community is able to resolve critical scientific and engineering problems quickly and with more precision. The results of these
 efforts align to DoW National Defense Strategy priorities, such as hypersonics, directed energy, autonomy, and artificial intelligence, and feed directly into the acquisition process by improving weapons system
 designs through an increased understanding of materials, aerodynamics, chemistry, fuels, acoustics, signal image recognition, electromagnetics, and other areas of basic and applied research as well as enabling
 advanced test and evaluation environments that allow synthetic scene generation, automatic control systems and virtual test environments. As such, HPC has been identified as a key enabling technology
 essential to achieving the objectives of the DoW's Science and Technology (S&T), Test and Evaluation (T&E), and acquisition communities. The program deploys compute-intensive and data-intensive systems
 to provide world-class HPC capabilities to the DoW-wide user community.

 The HPC Modernization program provides focused modernization efforts crafted to ensure DoW's S&T and T&E communities are supported with current generation supercomputing capabilities. The HPC
 modernization program resulted from congressional language that recognized supercomputing as a national strategic asset and directed the DoW to focus on supercomputing modernization at laboratories and
 test centers to keep its forces and military systems on the leading technological edge.$$, $$$$, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":100,"current_claimer_pid":"P_2035_L127","current_claimer_score":93.1,"margin":6.9,"src_li":86,"src_title":"High Perf Computing Mod Pgm (HPCMP)","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Army/Other_Procurement - BA2 - Communications & Electronics.pdf$$, 560, 560, $$679182db0afca25b$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L129$$, 2027, $$The Department of War (DoW) High Performance Computing (HPC) Modernization Program, managed by the Army, supports the needs of all services for technological superiority and military dominance on
 the battlefield by providing advanced computational services to U.S. weapons system scientists and engineers. By exploiting continuous advances in high performance computing technology, the Defense
 Research, Development, Test and Evaluation (RDT&E), and acquisition engineering community is able to resolve critical scientific and engineering problems quickly and with more precision. The results of these
 efforts align to DoW National Defense Strategy priorities, such as hypersonics, directed energy, autonomy, and artificial intelligence, and feed directly into the acquisition process by improving weapons system
 designs through an increased understanding of materials, aerodynamics, chemistry, fuels, acoustics, signal image recognition, electromagnetics, and other areas of basic and applied research as well as enabling
 advanced test and evaluation environments that allow synthetic scene generation, automatic control systems and virtual test environments. As such, HPC has been identified as a key enabling technology
 essential to achieving the objectives of the DoW's Science and Technology (S&T), Test and Evaluation (T&E), and acquisition communities. The program deploys compute-intensive and data-intensive systems
 to provide world-class HPC capabilities to the DoW-wide user community.

 The HPC Modernization program provides focused modernization efforts crafted to ensure DoW's S&T and T&E communities are supported with current generation supercomputing capabilities. The HPC
 modernization program resulted from congressional language that recognized supercomputing as a national strategic asset and directed the DoW to focus on supercomputing modernization at laboratories and
 test centers to keep its forces and military systems on the leading technological edge.$$, $$$$, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":100,"current_claimer_pid":"P_2035_L127","current_claimer_score":93.1,"margin":6.9,"src_li":86,"src_title":"High Perf Computing Mod Pgm (HPCMP)","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Army/Other_Procurement - BA2 - Communications & Electronics.pdf$$, 560, 560, $$62d312ace5e8fa94$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L138$$, 2026, $$Base Defense Systems (BDS) includes Non-Intrusive Inspection System (NIIS) (M90108), Ground-Based Operational Surveillance System (Expeditionary) (G-BOSS(E)) (M90212), and Security Surveillance
 System (SSS) (M90220) [formerly known as Tactical Security System (TSS)].

 Non-Intrusive Inspection System (NIIS) (M90108) is a family of systems that inspects for the presence of explosives, weapons and other contraband in vehicles, cargo containers and personnel from a distance
 providing stand-off ballistic and blast protection. All systems are either mobile or fully re-locatable. It is a force multiplier that maximizes protection of personnel, equipment and installations while minimizing
 manpower requirements. NIIS provides the capability to non-intrusively inspect vehicles, cargo containers, baggage and personnel for the presence of explosives, weapons or other contraband which can kill or
 injure Soldiers and destroy critical warfighting materiel. NIIS supports the urgent need for Counter-Improvised Explosive Device equipment to support military operations.

 Ground-Based Operational Surveillance System (Expeditionary) (G-BOSS(E)) (M90212) will provide improved persistent surveillance capabilities, network integration and force protection capabilities utilizing
 advanced sensor configurations. G-BOSS(E) provides enhanced surveillance and observation in expeditionary environments utilizing modular trailer-based sensor configurations; Medium variant (mid-sensor
 height) for small to medium size bases, and Heavy variant (high-level sensor height) for large contingency base camps. G-BOSS(E) will operate in a stand-alone mode or as part of an integrated network utilizing
 government-owned software, be easily operated and maintained, and be rugged enough to support employment in expeditionary operations worldwide. G-BOSS(E) achieved First Unit Equipped (FUE) in 2nd
 Quarter / FY 2025 and is currently supporting Joint Task Force - Southern Border (JTF-SB) with 12 systems. An additional 14 systems are planned to be fielded in support of JTF-SB in 2nd Quarter / FY 2026.
 The program is approved for Transition to Sustainment (T2S) in FY 2028.

 Security Surveillance System (SSS) (M90220) [formerly known as Tactical Security System (TSS)] provides a modular, scalable, lightweight, rapidly deployable, ground based security and surveillance Family of
 Systems designed for hasty emplacement to support short and long term security, surveillance and detection missions. The system will be tailorable to support various missions including internment/resettlement
 operations; perimeter security; internal security within base camps or installations; and external security outside the perimeter. SSS will be employed at fixed, semi-fixed or expeditionary sites providing all
 weather imaging during daylight/twilight and during periods of limited visibility regardless of environmental conditions to enhance the Commander's situational awareness and increase Soldier survivability. SSS is
 designed to be employed as a standalone force protection system, in a layered effort or integrated with additional force protection systems including motion, acoustic, seismic, surface and subterranean detection
 technologies. SSS will address four of the five base camp core protection/security capabilities identified in the IBD Concept of Operations including perimeter security, entry control, persistent surveillance and
 warning and alerting. SSS can be employed in support of contingency, short-notice, early-entry operations in a variety of weather and terrain from open desert to complex urban environments. SSS will assist
 in countering individuals and provide clandestine observation of detainees, individuals, either on foot or in vehicles from intruding into areas designated for security purposes. SSS will allow the Commander to$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                      Date: April 2026
