INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L191$$, 2027, $$Parent G02510 Test Equipment Modernization (TEMOD) contains multiple Resourced funding lines that procure different types/variants of test equipment with varied unit costs. Given the mix of procured
 equipment changes year-to-year, the composite unit cost at the parent funding line will also be variable. TEMOD procurements directly support the Army's warfighting strategy by maintaining missile, aviation, air-
 defense, and communication systems that preserve command, control and communication systems on the battlefield. The TEMOD family of test systems provides combatant commanders with lethality and the
 tactical overmatch necessary to win the nation's future conflicts.

 TEMOD includes Calibration Sets Equipment (CALSETS), Communications Test Equipment (CTE) and General Purpose Electronic Test Equipment (GPETE) funding lines. The TEMOD family of products
 provide equipment and systems which are vital to maintaining readiness of Army combat and combat support systems and support U.S. Army Transformation and Training Command (Future Vertical Lift; Long
 Range Precision Fires; Network Command, Control, Communications and Intelligence (C3I); Soldier Lethality; Air and Missile Defense and Next Generation Combat Vehicle) weapon systems.

 The Calibration Sets Equipment (CALSETS) program consists of calibration instrumentation housed in fixed facilities or contained within tactical shelters with accompanying power generation equipment. The
 CALSETS instrumentation provides support to maintenance units and area support organizations from brigade to multi-theater sustainment operations and ensures a cascading transfer of precision accuracy
 originating from the US National Institute of Standards and Technology (NIST). The calibration sets are designed to support 90 percent of the Army Test, Measurement and Diagnostic Equipment (TMDE)
 workload with an objective of 98 percent. The instruments and equipment procured through this program are assembled into several set configurations (AN/GSM-286, AN/GSM-287, AN/GSM-439, AN/GSM-440,
 AN/GSM-442, AN/GSM-26(V)1, AN/GSM-26(V)2 and Secondary Reference) and two tactical calibration shelters (AN/GSM-705 and AN/GSM-421A(V)2). These calibration standards sets are integral to verifying
 the accuracy of all TMDE with mandated traceability to accuracy standards. State-of-the-art calibration equipment is required to ensure that advanced technology weapons and systems are maintained at the
 required state of operational readiness. Systems supported by the Calibration Sets include, but are not limited to, Unmanned Aircraft Systems (UAS); military signal and electronic intelligence operations; tactical
 and strategic communications (Single Channel Ground and Airborne Radio System (SINCGARS)); ground, missile and aviation platforms such as the Army Family of Medium Tactical Vehicles (FMTV), Abrams,
 Multiple Launch Rocket System, Patriot, Apache, Blackhawk and Chinook; and the CFT weapon systems.

 The Communications Test Equipment (CTE) line provides for acquisition of the TS-4549 Radio Test Set (RTS). The RTS will be used to test, troubleshoot and repair Army radios down to the circuit card level.
 It supports both ground and air communication systems including legacy SINCGARS radios and tomorrow's Software Defined radios. The RTS will also be expandable and upgradeable to support future radio
 systems including the Army's investment in the Combat Net Radio (CNR) program and the Handheld, Man-pack, and Small Form Fit Radios (HMS) program. The RTS will replace an obsolete bench-level radio
 test set that is unable to support the Army's emerging radio platforms.$$, NULL, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":97.5,"current_claimer_pid":"P_2035_L174","current_claimer_score":30.8,"margin":66.8,"src_li":118,"src_title":"Test Equipment Modernization (TEMOD)","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Army/Other Procurement - BA3 & 4 - Other Support Equipment & Initial Spares.pdf$$, 496, 496, $$ece0ff0b783272db$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L193$$, 2027, $$Parent G02510 Test Equipment Modernization (TEMOD) contains multiple Resourced funding lines that procure different types/variants of test equipment with varied unit costs. Given the mix of procured
 equipment changes year-to-year, the composite unit cost at the parent funding line will also be variable. TEMOD procurements directly support the Army's warfighting strategy by maintaining missile, aviation, air-
 defense, and communication systems that preserve command, control and communication systems on the battlefield. The TEMOD family of test systems provides combatant commanders with lethality and the
 tactical overmatch necessary to win the nation's future conflicts.

 TEMOD includes Calibration Sets Equipment (CALSETS), Communications Test Equipment (CTE) and General Purpose Electronic Test Equipment (GPETE) funding lines. The TEMOD family of products
 provide equipment and systems which are vital to maintaining readiness of Army combat and combat support systems and support U.S. Army Transformation and Training Command (Future Vertical Lift; Long
 Range Precision Fires; Network Command, Control, Communications and Intelligence (C3I); Soldier Lethality; Air and Missile Defense and Next Generation Combat Vehicle) weapon systems.

 The Calibration Sets Equipment (CALSETS) program consists of calibration instrumentation housed in fixed facilities or contained within tactical shelters with accompanying power generation equipment. The
 CALSETS instrumentation provides support to maintenance units and area support organizations from brigade to multi-theater sustainment operations and ensures a cascading transfer of precision accuracy
 originating from the US National Institute of Standards and Technology (NIST). The calibration sets are designed to support 90 percent of the Army Test, Measurement and Diagnostic Equipment (TMDE)
 workload with an objective of 98 percent. The instruments and equipment procured through this program are assembled into several set configurations (AN/GSM-286, AN/GSM-287, AN/GSM-439, AN/GSM-440,
 AN/GSM-442, AN/GSM-26(V)1, AN/GSM-26(V)2 and Secondary Reference) and two tactical calibration shelters (AN/GSM-705 and AN/GSM-421A(V)2). These calibration standards sets are integral to verifying
 the accuracy of all TMDE with mandated traceability to accuracy standards. State-of-the-art calibration equipment is required to ensure that advanced technology weapons and systems are maintained at the
 required state of operational readiness. Systems supported by the Calibration Sets include, but are not limited to, Unmanned Aircraft Systems (UAS); military signal and electronic intelligence operations; tactical
 and strategic communications (Single Channel Ground and Airborne Radio System (SINCGARS)); ground, missile and aviation platforms such as the Army Family of Medium Tactical Vehicles (FMTV), Abrams,
 Multiple Launch Rocket System, Patriot, Apache, Blackhawk and Chinook; and the CFT weapon systems.

 The Communications Test Equipment (CTE) line provides for acquisition of the TS-4549 Radio Test Set (RTS). The RTS will be used to test, troubleshoot and repair Army radios down to the circuit card level.
 It supports both ground and air communication systems including legacy SINCGARS radios and tomorrow's Software Defined radios. The RTS will also be expandable and upgradeable to support future radio
 systems including the Army's investment in the Combat Net Radio (CNR) program and the Handheld, Man-pack, and Small Form Fit Radios (HMS) program. The RTS will replace an obsolete bench-level radio
 test set that is unable to support the Army's emerging radio platforms.$$, NULL, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":83.9,"current_claimer_pid":"P_2035_L174","current_claimer_score":30.8,"margin":53.2,"src_li":118,"src_title":"Test Equipment Modernization (TEMOD)","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Army/Other Procurement - BA3 & 4 - Other Support Equipment & Initial Spares.pdf$$, 496, 496, $$6779e3e27e4afb02$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L197$$, 2027, $$The Firefighter Individual Requirements Set (FIRES) is a set of hardware components necessary for directly supporting MOS 12M Firefighters to perform Mission Essential Wartime Requirements (MEWR) duties
 and is a critical life support & safety system for Soldiers. FIRES must be modernized to meet National Fire Protection Association (NFPA) standards. The set contains Knife Rescue, Flashlight LED, Rescue
 Tool, Backpack Black, Hydration Reservoir, Chest Harness Radio, Helmet Light, Fire Shelter, Face Mask, Protective Mask Canister, Air Cylinder Assembly, Black Case. The Self-Contained Breathing Apparatus
 (SCBA) is the air mask and air cylinder that firefighters wear to protect their lungs and prevent smoke inhalation during a firefighting mission. The SCBA also contains a Powered Air Purifying Respirator (PAPR)
 when missions require actively filtered air or durations longer than a bottle can supply.

 The Material Handling Equipment (MHE) Modification of In-Service Equipment program funds system modifications and modernization initiatives across the MHE portfolio, to include the Rough Terrain Container
 Handler (RTCH); All-Terrain Lifter, Army System (ATLAS); and Light Capability Rough Terrain Forklift (LCRTF). These improvements will decrease rising sustainment costs and bridge the gap until new system
 procurement in future years. These programs serve as critical enablers to the operational force by providing the capabilities necessary to (1) clear landing zones of supplies and equipment, load and unload
 combat vehicles and aircraft as well as moving some artillery assets, ammunition and supplies and (2) perform port opening operations, logistics movement, and unloading and loading of containers that handle
 break-bulk cargo at seaports, railheads, and airports. The LCRTF is the only rugged forklift in the U.S. Army's inventory which can rapidly enter, pack, and unpack ISO containers, load and unload tactical
 vehicles and trailers, and lift and move light equipment and cargo. The RTCH represents a key enabler during Joint Logistics Over the Shore Operations (JLOTS) and lifts, moves, and stacks 20- and 40-foot ISO
 freight containers. In addition, program funds support the procurement and fielding of RTCH Special Tools Kits required to meet Field Level Maintenance requirements per the current Technical Manual for the
 aging legacy fleet.

 The Construction Equipment (CE) Modification of In-Service Equipment program funds system modifications and modernization initiatives across the CE portfolio, to include the High Mobility Engineer Excavator
 (HMEE); Engineer Rapid Airfield Construction Capability (ERACC) for Dozers, Graders, Scrapers; Family of Loaders (FOL); Skid Steer Loader (SSL); Tractor Full Tracked; Grader; Scrapers and DEUCE;
 and Hydraulic Excavators (HYEX). These programs serve as critical enablers to the operational force by providing the capabilities necessary (1) general construction tasks; (2) to construct, maintain and
 repair airfields, runways, main supply routes, logistical facilities, roads, helipads, and ports of entry/debarkation; (3) to repair and keep open Line of Communications resulting in increased force mobility,
 maneuverability, deployability, sustainability; and (4) to enhance force infrastructure protection across a range of military operations. Improvements made to these systems will decrease rising sustainment costs
 and bridge the gap until new system procurement in future years.

 Army Watercraft Systems (AWS) support Dynamic Force Repositioning (DFR) and provides the Combatant and Multi-Domain Task Force Commander with organic waterborne lift capability that can deliver
 today's Army maneuver platforms and equipment, and supply bulk fuel and water across the full spectrum of operations with increased speed and lower draft; and mitigates anti-access/area denial (A2/AD) threat$$, NULL, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":100,"current_claimer_pid":"P_2035_L196","current_claimer_score":100.0,"margin":0.0,"src_li":121,"src_title":"Modification Of In-Svc Equipment (OPA-3)","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Army/Other Procurement - BA3 & 4 - Other Support Equipment & Initial Spares.pdf$$, 535, 535, $$323d9e7cb7e54be9$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
